challenges.solution:
/* Token architecture (see lesson.md for full set) */
:root { --color-primary: #3b82f6; --color-surface: #ffffff; --color-text: #0f172a; --color-text-secondary: #475569; --color-border: #e2e8f0; --spacing-sm: 8px; --spacing-md: 16px; --spacing-lg: 24px; --radius-md: 8px; --radius-lg: 12px; --font-sans: system-ui, sans-serif; --font-size-base: 1rem; --shadow-md: 0 4px 6px rgba(0,0,0,0.07); }

[data-theme="dark"] { --color-primary: #60a5fa; --color-surface: #1e1e2e; --color-text: #cdd6f4; --color-text-secondary: #a6adc8; --color-border: #45475a; --shadow-md: 0 4px 6px rgba(0,0,0,0.4); }

[data-theme="high-contrast"] { --color-primary: #0000ff; --color-surface: #ffffff; --color-text: #000000; --color-text-secondary: #000000; --color-border: #000000; --shadow-md: none; }

/* JS */
function setTheme(theme) { document.documentElement.setAttribute('data-theme', theme); localStorage.setItem('theme', theme); }
const saved = localStorage.getItem('theme'); if (saved) setTheme(saved);

