challenges.solution:
/* Refactored design system */
@layer settings, generic, elements, objects, components, utilities;

@layer settings {
  :root {
    --color-primary: #667eea;
    --color-danger: #e74c3c;
    --color-surface: #ffffff;
    --color-text: #333333;
    --spacing-md: 16px;
    --spacing-lg: 24px;
    --radius-md: 8px;
    --radius-lg: 12px;
    --font-size-base: 1rem;
    --font-size-heading: 1.5rem;
    --shadow: 0 2px 8px rgba(0,0,0,0.1);
  }
}

@layer components {
  .c-card { background: var(--color-surface); padding: var(--spacing-lg); border-radius: var(--radius-lg); box-shadow: var(--shadow); }
  .c-card__title { font-size: var(--font-size-heading); color: var(--color-text); margin-bottom: var(--spacing-md); }

  .c-btn { background: var(--color-primary); color: white; padding: var(--spacing-md) var(--spacing-lg); border-radius: var(--radius-md); border: none; font-size: var(--font-size-base); cursor: pointer; transition: opacity 0.2s; }
  .c-btn:hover { opacity: 0.9; }
  .c-btn:focus-visible { outline: 2px solid var(--color-primary); outline-offset: 2px; }
  .c-btn--danger { background: var(--color-danger); }
}

@layer utilities {
  .u-mt-lg { margin-top: var(--spacing-lg); }
}

